#!/usr/bin/env python3
"""
Gnosis polyglot execution harness for Python.

Protocol: reads JSON request from stdin. For direct function calls it imports
the target module and calls the named function. For compatibility execution it
can also install lightweight Flask and FastAPI shims, capture app topology
during import, and replay HTTP request envelopes in place.
"""

import asyncio
import base64
import importlib.util
import inspect
import io
import json
import os
import re
import sys
import traceback
import types
from urllib.parse import parse_qs


ROUTE_PARAM_RE = re.compile(
    r"<(?:(?P<converter>[A-Za-z_][A-Za-z0-9_]*):)?(?P<name>[A-Za-z_][A-Za-z0-9_]*)>"
)
FASTAPI_ROUTE_PARAM_RE = re.compile(
    r"\{(?P<name>[A-Za-z_][A-Za-z0-9_]*)\}"
)


class HeaderMap(dict):
    """Minimal case-insensitive header map."""

    def __init__(self, data=None):
        super().__init__()
        for key, value in (data or {}).items():
            super().__setitem__(str(key).lower(), value)

    def __getitem__(self, key):
        return super().__getitem__(str(key).lower())

    def __contains__(self, key):
        return super().__contains__(str(key).lower())

    def get(self, key, default=None):
        return super().get(str(key).lower(), default)

    def setdefault(self, key, default=None):
        return super().setdefault(str(key).lower(), default)


class QueryArgs(dict):
    """Minimal request.args shape with Flask-like get semantics."""

    @classmethod
    def from_query(cls, query):
        parsed = parse_qs((query or "").lstrip("?"), keep_blank_values=True)
        flattened = {key: values[-1] if values else "" for key, values in parsed.items()}
        return cls(flattened)

    def get(self, key, default=None):
        return super().get(key, default)


class CompatibilityResponse:
    """Minimal Flask-compatible response object."""

    def __init__(self, body=b"", status=200, headers=None, mimetype=None):
        if isinstance(body, str):
            body = body.encode("utf-8")
        elif isinstance(body, bytearray):
            body = bytes(body)
        elif body is None:
            body = b""

        self.body = body
        self.status_code = int(status)
        self.headers = dict(headers or {})
        if mimetype and "Content-Type" not in self.headers:
            self.headers["Content-Type"] = mimetype

    def set_data(self, data):
        if isinstance(data, str):
            self.body = data.encode("utf-8")
        elif isinstance(data, bytearray):
            self.body = bytes(data)
        else:
            self.body = data

    def get_data(self):
        return self.body


class RequestState:
    """Compatibility request state exposed through the Flask request proxy."""

    def __init__(self, request_envelope):
        body = request_envelope.get("body") or {}
        raw_body = body.get("value", "")
        self.method = str(request_envelope.get("method", "GET")).upper()
        self.path = request_envelope.get("path", "/")
        self.query_string = request_envelope.get("query", "")
        self.headers = HeaderMap(request_envelope.get("headers") or {})
        self.args = QueryArgs.from_query(self.query_string)
        self.data = (
            base64.b64decode(raw_body)
            if body.get("encoding") == "base64" and isinstance(raw_body, str)
            else b""
        )
        self.view_args = {}
        self._json_loaded = False
        self._json_value = None

    @property
    def json(self):
        return self.get_json(silent=True)

    def get_data(self):
        return self.data

    def get_json(self, force=False, silent=False):
        if self._json_loaded:
            return self._json_value

        content_type = self.headers.get("content-type", "")
        should_parse = force or "application/json" in content_type.lower()
        if not should_parse:
            if silent:
                return None
            raise ValueError("request body is not JSON")

        try:
            decoded = self.data.decode("utf-8")
            self._json_value = json.loads(decoded) if decoded else None
            self._json_loaded = True
            return self._json_value
        except Exception:
            if silent:
                self._json_loaded = True
                self._json_value = None
                return None
            raise


_current_request = None
_registered_flask_apps = []
_registered_fastapi_apps = []


class ParameterSource:
    def __init__(self, source, default=None, alias=None):
        self.source = source
        self.default = default
        self.alias = alias


def Query(default=None, alias=None):
    return ParameterSource("query", default=default, alias=alias)


def Path(default=None, alias=None):
    return ParameterSource("path", default=default, alias=alias)


def Body(default=None, alias=None):
    return ParameterSource("body", default=default, alias=alias)


class CompatBaseModel:
    def __init__(self, **values):
        annotations = getattr(self.__class__, "__annotations__", {})
        for key in annotations:
            setattr(self, key, values.get(key))
        for key, value in values.items():
            if not hasattr(self, key):
                setattr(self, key, value)

    def model_dump(self):
        annotations = getattr(self.__class__, "__annotations__", {})
        return {key: getattr(self, key, None) for key in annotations}

    def dict(self):
        return self.model_dump()


class FastAPIHTTPException(Exception):
    def __init__(self, status_code, detail=None, headers=None):
        super().__init__(detail)
        self.status_code = int(status_code)
        self.detail = detail
        self.headers = dict(headers or {})


def _require_current_request():
    if _current_request is None:
        raise RuntimeError("request is only available during compatibility execution")
    return _current_request


class RequestProxy:
    """Late-bound proxy that mimics flask.request."""

    def __getattr__(self, name):
        return getattr(_require_current_request(), name)

    def __setattr__(self, name, value):
        setattr(_require_current_request(), name, value)


def _run_maybe_async(value):
    if inspect.isawaitable(value):
        return asyncio.run(value)
    return value


async def _await_maybe_async(value):
    if inspect.isawaitable(value):
        return await value
    return value


def _coerce_status(value):
    if value is None:
        return None
    return int(value)


def jsonify(*args, **kwargs):
    if args and kwargs:
        raise TypeError("jsonify() accepts either args or kwargs")
    if not args and not kwargs:
        payload = None
    elif len(args) == 1 and not kwargs:
        payload = args[0]
    elif args and not kwargs:
        payload = list(args)
    else:
        payload = kwargs

    return CompatibilityResponse(
        json.dumps(payload).encode("utf-8"),
        headers={"Content-Type": "application/json; charset=utf-8"},
    )


def normalize_response(value):
    body = value
    status = None
    headers = None

    if isinstance(value, tuple):
        if len(value) == 2:
            body, second = value
            if isinstance(second, dict):
                headers = second
            else:
                status = second
        elif len(value) == 3:
            body, status, headers = value
        else:
            raise ValueError("unsupported Flask response tuple shape")

    if isinstance(body, CompatibilityResponse):
        response = body
    elif isinstance(body, CompatBaseModel):
        response = CompatibilityResponse(
            json.dumps(body.model_dump()).encode("utf-8"),
            headers={"Content-Type": "application/json; charset=utf-8"},
        )
    elif isinstance(body, (dict, list)):
        response = CompatibilityResponse(
            json.dumps(body).encode("utf-8"),
            headers={"Content-Type": "application/json; charset=utf-8"},
        )
    elif isinstance(body, (bytes, bytearray)):
        response = CompatibilityResponse(bytes(body), mimetype="application/octet-stream")
    else:
        text = "" if body is None else str(body)
        response = CompatibilityResponse(text, mimetype="text/plain; charset=utf-8")

    if status is not None:
        response.status_code = _coerce_status(status)
    if headers:
        response.headers.update(headers)
    return response


def make_response(value, status=None, headers=None):
    response = normalize_response(value)
    if status is not None:
        response.status_code = _coerce_status(status)
    if headers:
        response.headers.update(headers)
    return response


def compile_route_rule(rule):
    converters = {}
    pattern_parts = ["^"]
    last_index = 0

    for match in ROUTE_PARAM_RE.finditer(rule):
        pattern_parts.append(re.escape(rule[last_index : match.start()]))

        converter = match.group("converter") or "string"
        name = match.group("name")
        converters[name] = converter

        if converter == "int":
            pattern_parts.append(rf"(?P<{name}>\d+)")
        elif converter == "float":
            pattern_parts.append(rf"(?P<{name}>[0-9]+(?:\.[0-9]+)?)")
        elif converter == "path":
            pattern_parts.append(rf"(?P<{name}>.+)")
        else:
            pattern_parts.append(rf"(?P<{name}>[^/]+)")

        last_index = match.end()

    pattern_parts.append(re.escape(rule[last_index:]))
    pattern_parts.append("$")
    return re.compile("".join(pattern_parts)), converters


def compile_fastapi_route_rule(rule):
    pattern_parts = ["^"]
    param_names = []
    last_index = 0

    for match in FASTAPI_ROUTE_PARAM_RE.finditer(rule):
        pattern_parts.append(re.escape(rule[last_index : match.start()]))
        name = match.group("name")
        param_names.append(name)
        pattern_parts.append(rf"(?P<{name}>[^/]+)")
        last_index = match.end()

    pattern_parts.append(re.escape(rule[last_index:]))
    pattern_parts.append("$")
    return re.compile("".join(pattern_parts)), param_names


def coerce_route_params(params, converters):
    coerced = {}
    for key, value in params.items():
        converter = converters.get(key, "string")
        if converter == "int":
            coerced[key] = int(value)
        elif converter == "float":
            coerced[key] = float(value)
        else:
            coerced[key] = value
    return coerced


class FlaskRoute:
    def __init__(self, method, rule, handler):
        self.method = method.upper()
        self.rule = rule
        self.handler = handler
        self.pattern, self.converters = compile_route_rule(rule)

    def match(self, method, path):
        if self.method != method.upper():
            return None

        match = self.pattern.match(path)
        if not match:
            return None

        return coerce_route_params(match.groupdict(), self.converters)


class FlaskCompatApp:
    def __init__(self, import_name):
        self.import_name = import_name
        self._routes = []
        self._before_request = []
        self._after_request = []
        self._run_kwargs = {}
        _registered_flask_apps.append(self)

    def route(self, rule, methods=None):
        normalized_methods = [str(method).upper() for method in (methods or ["GET"])]

        def decorator(handler):
            for method in normalized_methods:
                self._routes.append(FlaskRoute(method, rule, handler))
            return handler

        return decorator

    def get(self, rule):
        return self.route(rule, methods=["GET"])

    def post(self, rule):
        return self.route(rule, methods=["POST"])

    def put(self, rule):
        return self.route(rule, methods=["PUT"])

    def delete(self, rule):
        return self.route(rule, methods=["DELETE"])

    def patch(self, rule):
        return self.route(rule, methods=["PATCH"])

    def before_request(self, handler):
        self._before_request.append(handler)
        return handler

    def after_request(self, handler):
        self._after_request.append(handler)
        return handler

    def run(self, *args, **kwargs):
        self._run_kwargs = dict(kwargs)
        return None

    def dispatch_compatibility_request(self, request_envelope):
        global _current_request

        method = request_envelope.get("method", "GET")
        path = request_envelope.get("path", "/")
        matched_route = None
        matched_params = None

        for route in self._routes:
            params = route.match(method, path)
            if params is not None:
                matched_route = route
                matched_params = params
                break

        if matched_route is None:
            return {"matched": False}

        _current_request = RequestState(request_envelope)
        _current_request.view_args = matched_params or {}

        try:
            response = None

            for middleware in self._before_request:
                middleware_result = _run_maybe_async(middleware())
                if middleware_result is not None:
                    response = normalize_response(middleware_result)
                    break

            if response is None:
                handler_result = _run_maybe_async(
                    matched_route.handler(**(matched_params or {}))
                )
                response = normalize_response(handler_result)

            for middleware in self._after_request:
                middleware_result = _run_maybe_async(middleware(response))
                if middleware_result is not None:
                    response = normalize_response(middleware_result)

            body = response.get_data()
            encoded_body = base64.b64encode(body).decode("ascii") if body else ""

            return {
                "matched": True,
                "response": {
                    "status": response.status_code,
                    "headers": response.headers,
                    "body": {
                        "encoding": "base64",
                        "value": encoded_body,
                    },
                },
            }
        finally:
            _current_request = None


class FastAPIRoute:
    def __init__(self, method, rule, handler, status_code=None):
        self.method = method.upper()
        self.rule = rule
        self.handler = handler
        self.status_code = status_code
        self.pattern, self.param_names = compile_fastapi_route_rule(rule)

    def match(self, method, path):
        if self.method != method.upper():
            return None

        match = self.pattern.match(path)
        if not match:
            return None

        return match.groupdict()


def _is_fastapi_request_parameter(parameter):
    annotation = parameter.annotation
    return (
        parameter.name == "request"
        or annotation is RequestState
        or getattr(annotation, "__name__", "") == "Request"
    )


def _coerce_fastapi_value(annotation, value):
    if value is None or annotation is inspect._empty:
        return value

    if annotation is str:
        return str(value)
    if annotation is int:
        return int(value)
    if annotation is float:
        return float(value)
    if annotation is bool:
        if isinstance(value, bool):
            return value
        return str(value).lower() in {"1", "true", "yes", "on"}
    if annotation is dict and isinstance(value, dict):
        return value
    if annotation is list and isinstance(value, list):
        return value
    if isinstance(annotation, type) and issubclass(annotation, CompatBaseModel):
        if isinstance(value, dict):
            return annotation(**value)
        return annotation(value=value)

    return value


def _infer_fastapi_parameter_source(parameter, request_state, parsed_body):
    default = parameter.default
    if isinstance(default, ParameterSource):
        return default.source

    if request_state.method in {"POST", "PUT", "PATCH"} and parsed_body is not None:
        return "body"

    return "query"


def bind_fastapi_arguments(handler, request_state, path_params):
    signature = inspect.signature(handler)
    parsed_body = request_state.get_json(silent=True)
    non_path_parameters = [
        parameter
        for parameter in signature.parameters.values()
        if parameter.name not in path_params
        and not _is_fastapi_request_parameter(parameter)
    ]
    body_candidates = [
        parameter
        for parameter in non_path_parameters
        if _infer_fastapi_parameter_source(parameter, request_state, parsed_body)
        == "body"
    ]

    kwargs = {}
    for parameter in signature.parameters.values():
        if parameter.name in path_params:
            value = path_params[parameter.name]
            kwargs[parameter.name] = _coerce_fastapi_value(
                parameter.annotation, value
            )
            continue

        if _is_fastapi_request_parameter(parameter):
            kwargs[parameter.name] = request_state
            continue

        default = parameter.default
        alias = (
            default.alias
            if isinstance(default, ParameterSource) and default.alias
            else parameter.name
        )
        source = _infer_fastapi_parameter_source(
            parameter, request_state, parsed_body
        )

        if source == "query":
            value = request_state.args.get(alias)
        else:
            if isinstance(parsed_body, dict):
                if len(body_candidates) == 1 and alias not in parsed_body:
                    value = parsed_body
                else:
                    value = parsed_body.get(alias)
                    if value is None and len(body_candidates) == 1:
                        value = parsed_body
            else:
                value = parsed_body

        value = _coerce_fastapi_value(parameter.annotation, value)
        if value is None:
            if isinstance(default, ParameterSource):
                value = default.default
            elif default is not inspect._empty:
                value = default

        kwargs[parameter.name] = value

    return kwargs


class FastAPICompatApp:
    def __init__(self, *args, **kwargs):
        self._routes = []
        self._middleware = []
        _registered_fastapi_apps.append(self)

    def api_route(self, rule, methods=None, status_code=None):
        normalized_methods = [str(method).upper() for method in (methods or ["GET"])]

        def decorator(handler):
            for method in normalized_methods:
                self._routes.append(
                    FastAPIRoute(
                        method,
                        rule,
                        handler,
                        status_code=status_code,
                    )
                )
            return handler

        return decorator

    def get(self, rule, status_code=None):
        return self.api_route(rule, methods=["GET"], status_code=status_code)

    def post(self, rule, status_code=None):
        return self.api_route(rule, methods=["POST"], status_code=status_code)

    def put(self, rule, status_code=None):
        return self.api_route(rule, methods=["PUT"], status_code=status_code)

    def delete(self, rule, status_code=None):
        return self.api_route(rule, methods=["DELETE"], status_code=status_code)

    def patch(self, rule, status_code=None):
        return self.api_route(rule, methods=["PATCH"], status_code=status_code)

    def add_api_route(self, rule, handler, methods=None, status_code=None):
        return self.api_route(rule, methods=methods, status_code=status_code)(handler)

    def middleware(self, kind):
        if kind != "http":
            raise ValueError("only FastAPI HTTP middleware is supported")

        def decorator(handler):
            self._middleware.append(handler)
            return handler

        return decorator

    def exception_handler(self, *_args, **_kwargs):
        def decorator(handler):
            return handler

        return decorator

    def dispatch_compatibility_request(self, request_envelope):
        global _current_request

        method = request_envelope.get("method", "GET")
        path = request_envelope.get("path", "/")
        matched_route = None
        matched_params = None

        for route in self._routes:
            params = route.match(method, path)
            if params is not None:
                matched_route = route
                matched_params = params
                break

        if matched_route is None:
            return {"matched": False}

        _current_request = RequestState(request_envelope)
        _current_request.view_args = matched_params or {}

        try:
            async def invoke_handler():
                bound_args = bind_fastapi_arguments(
                    matched_route.handler,
                    _current_request,
                    matched_params or {},
                )
                try:
                    result = await _await_maybe_async(
                        matched_route.handler(**bound_args)
                    )
                except FastAPIHTTPException as exc:
                    return normalize_response(
                        (
                            {"detail": exc.detail},
                            exc.status_code,
                            exc.headers,
                        )
                    )
                response = normalize_response(result)
                if (
                    matched_route.status_code is not None
                    and response.status_code == 200
                ):
                    response.status_code = int(matched_route.status_code)
                return response

            async def terminal_handler(_request):
                return await invoke_handler()

            next_handler = terminal_handler
            for middleware in reversed(self._middleware):
                previous_handler = next_handler

                def wrap_handler(active_middleware, downstream_handler):
                    async def wrapped(request_state):
                        result = active_middleware(request_state, downstream_handler)
                        if inspect.isawaitable(result):
                            result = await result
                        if isinstance(result, CompatibilityResponse):
                            return result
                        return normalize_response(result)

                    return wrapped

                next_handler = wrap_handler(middleware, previous_handler)

            response = _run_maybe_async(next_handler(_current_request))
            body = response.get_data()
            encoded_body = base64.b64encode(body).decode("ascii") if body else ""

            return {
                "matched": True,
                "response": {
                    "status": response.status_code,
                    "headers": response.headers,
                    "body": {
                        "encoding": "base64",
                        "value": encoded_body,
                    },
                },
            }
        finally:
            _current_request = None


def install_flask_compat_module():
    flask_module = types.ModuleType("flask")
    flask_module.Flask = FlaskCompatApp
    flask_module.Response = CompatibilityResponse
    flask_module.request = RequestProxy()
    flask_module.jsonify = jsonify
    flask_module.make_response = make_response
    flask_module.__all__ = ["Flask", "Response", "jsonify", "make_response", "request"]
    previous = sys.modules.get("flask")
    sys.modules["flask"] = flask_module
    return previous


def install_fastapi_compat_modules():
    fastapi_module = types.ModuleType("fastapi")
    fastapi_module.FastAPI = FastAPICompatApp
    fastapi_module.Query = Query
    fastapi_module.Path = Path
    fastapi_module.Body = Body
    fastapi_module.Request = RequestState
    fastapi_module.Response = CompatibilityResponse
    fastapi_module.HTTPException = FastAPIHTTPException
    fastapi_module.__all__ = [
        "FastAPI",
        "Query",
        "Path",
        "Body",
        "Request",
        "Response",
        "HTTPException",
    ]
    previous_fastapi = sys.modules.get("fastapi")
    sys.modules["fastapi"] = fastapi_module

    pydantic_module = types.ModuleType("pydantic")
    pydantic_module.BaseModel = CompatBaseModel
    pydantic_module.__all__ = ["BaseModel"]
    previous_pydantic = sys.modules.get("pydantic")
    sys.modules["pydantic"] = pydantic_module

    return previous_fastapi, previous_pydantic


def reset_python_service_compat_state():
    global _current_request
    _current_request = None
    _registered_flask_apps.clear()
    _registered_fastapi_apps.clear()


def load_module_from_path(file_path, module_name=None):
    file_dir = os.path.dirname(os.path.abspath(file_path))
    if file_dir not in sys.path:
        sys.path.insert(0, file_dir)

    if module_name is None:
        module_name = os.path.splitext(os.path.basename(file_path))[0]

    spec = importlib.util.spec_from_file_location(module_name, file_path)
    if spec is None or spec.loader is None:
        raise ImportError(f"Cannot load module from {file_path}")

    module = importlib.util.module_from_spec(spec)
    sys.modules[module_name] = module
    spec.loader.exec_module(module)
    return module_name, module


def execute_function(file_path, function_name, args):
    """Import a Python file and call the named function with args."""
    _, module = load_module_from_path(file_path)

    if not hasattr(module, function_name):
        module_name = os.path.splitext(os.path.basename(file_path))[0]
        raise AttributeError(f"Module '{module_name}' has no function '{function_name}'")

    func = getattr(module, function_name)
    if not callable(func):
        raise TypeError(f"'{function_name}' is not callable")

    return _run_maybe_async(func(*args))


def execute_compatibility(request):
    compatibility = request.get("compatibility")
    if not compatibility:
        raise ValueError("missing compatibility request")

    family = compatibility.get("family")
    framework = compatibility.get("framework")

    if family != "python-service":
        raise ValueError(f"unsupported compatibility family {family!r}")

    if framework not in {"flask", "fastapi"}:
        raise ValueError(f"unsupported Python service framework {framework!r}")

    previous_flask_module = None
    previous_fastapi_module = None
    previous_pydantic_module = None

    if framework == "flask":
        previous_flask_module = install_flask_compat_module()
    else:
        previous_fastapi_module, previous_pydantic_module = (
            install_fastapi_compat_modules()
        )

    reset_python_service_compat_state()

    file_path = request.get("filePath", "")
    module_name = f"_gnosis_{framework}_compat_{os.getpid()}_{abs(hash(file_path))}"

    try:
        _, module = load_module_from_path(file_path, module_name=module_name)
        app = getattr(module, "app", None)
        if framework == "flask":
            if not isinstance(app, FlaskCompatApp):
                app = _registered_flask_apps[-1] if _registered_flask_apps else None
            if app is None:
                raise RuntimeError(
                    f"failed to locate a Flask app while loading {os.path.basename(file_path)}"
                )
        else:
            if not isinstance(app, FastAPICompatApp):
                app = _registered_fastapi_apps[-1] if _registered_fastapi_apps else None
            if app is None:
                raise RuntimeError(
                    f"failed to locate a FastAPI app while loading {os.path.basename(file_path)}"
                )

        return app.dispatch_compatibility_request(compatibility.get("request") or {})
    finally:
        reset_python_service_compat_state()
        sys.modules.pop(module_name, None)
        if previous_flask_module is not None:
            sys.modules["flask"] = previous_flask_module
        else:
            sys.modules.pop("flask", None)
        if previous_fastapi_module is not None:
            sys.modules["fastapi"] = previous_fastapi_module
        else:
            sys.modules.pop("fastapi", None)
        if previous_pydantic_module is not None:
            sys.modules["pydantic"] = previous_pydantic_module
        else:
            sys.modules.pop("pydantic", None)


def main():
    raw_input = sys.stdin.read()
    if not raw_input.strip():
        json.dump(
            {"status": "error", "value": "empty input", "stdout": "", "stderr": ""},
            sys.stdout,
        )
        return

    try:
        request = json.loads(raw_input)
    except json.JSONDecodeError as e:
        json.dump(
            {
                "status": "error",
                "value": f"invalid JSON input: {e}",
                "stdout": "",
                "stderr": "",
            },
            sys.stdout,
        )
        return

    action = request.get("action", "execute")
    if action == "ping":
        json.dump(
            {"status": "ok", "value": "pong", "stdout": "", "stderr": ""},
            sys.stdout,
        )
        return

    file_path = request.get("filePath", "")
    function_name = request.get("functionName", "main")
    args = request.get("args", [])

    captured_stdout = io.StringIO()
    captured_stderr = io.StringIO()
    old_stdout = sys.stdout
    old_stderr = sys.stderr

    try:
        sys.stdout = captured_stdout
        sys.stderr = captured_stderr

        if request.get("compatibility") is not None:
            result = execute_compatibility(request)
        else:
            result = execute_function(file_path, function_name, args)

        sys.stdout = old_stdout
        sys.stderr = old_stderr

        try:
            json.dumps(result)
            value = result
        except (TypeError, ValueError):
            value = str(result)

        json.dump(
            {
                "status": "ok",
                "value": value,
                "stdout": captured_stdout.getvalue(),
                "stderr": captured_stderr.getvalue(),
            },
            sys.stdout,
        )

    except Exception:
        sys.stdout = old_stdout
        sys.stderr = old_stderr

        json.dump(
            {
                "status": "error",
                "value": traceback.format_exc(),
                "stdout": captured_stdout.getvalue(),
                "stderr": captured_stderr.getvalue(),
            },
            sys.stdout,
        )


if __name__ == "__main__":
    main()
